import{_ as a,o as e,c as r,a9 as p}from"./chunks/framework.D4xYp1Zt.js";const n="/images/why-im-always-late/Late1.png",s="/images/why-im-always-late/Latea.png",o="/images/why-im-always-late/Lateb.png",l="/images/why-im-always-late/Latec.png",i="/images/why-im-always-late/Late3.png",m="/images/why-im-always-late/Late4.png",h="/images/why-im-always-late/Late5.png",w="/images/why-im-always-late/Late6.png",g="/images/why-im-always-late/Late7.png",c="/images/why-im-always-late/Late8.png",y="/images/why-im-always-late/Late9.png",_="/images/why-im-always-late/Late10.png",u="/images/why-im-always-late/Late16.png",f="/images/why-im-always-late/Late17.png",b="/images/why-im-always-late/Late18.png",L="/images/why-im-always-late/Late19.png",d="/images/why-im-always-late/Late20.png",k="/images/why-im-always-late/Late21.png",P="/images/why-im-always-late/Late22.png",C="/images/why-im-always-late/Late23.png",I="/images/why-im-always-late/Late24.png",W="/images/why-im-always-late/Late25.png",x="/images/why-im-always-late/Late26.png",v="/images/why-im-always-late/PM1.png",A="/images/why-im-always-late/PM2.png",M="/images/why-im-always-late/PM31.png",q="/images/why-im-always-late/traffic1.png",S="/images/why-im-always-late/Cab1.png",T="/images/why-im-always-late/Cab2.png",B="/images/why-im-always-late/Cab31.png",O="/images/why-im-always-late/pinit_fg_en_rect_gray_20.png",R=JSON.parse(`{"title":"Why I'm Always Late","description":"","frontmatter":{"title":"Why I'm Always Late","titleZh":"为什么我总是迟到","date":"2015-07-07T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2015/07/why-im-always-late.html","slug":"why-im-always-late"},"headers":[],"relativePath":"posts/why-im-always-late.md","filePath":"posts/why-im-always-late.md","lastUpdated":1782886257000}`),K={name:"posts/why-im-always-late.md"};function $(D,t,E,H,N,V){return e(),r("div",null,[...t[0]||(t[0]=[p('<h1 id="为什么我总是迟到-·-why-i-m-always-late" tabindex="-1">为什么我总是迟到 · Why I&#39;m Always Late <a class="header-anchor" href="#为什么我总是迟到-·-why-i-m-always-late" aria-label="Permalink to &quot;为什么我总是迟到 · Why I&#39;m Always Late&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2015/07/why-im-always-late.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2015/07/why-im-always-late.html</a> · 2015-07-07</p></blockquote><p>今天早上我被 Andrew 发来的一条短信叫醒。是个链接:</p><p><a href="http://elitedaily.com/life/culture/optimistic-people-have-one-thing-common-always-late/1097735/" target="_blank" rel="noreferrer">http://elitedaily.com/life/culture/optimistic-people-have-one-thing-common-always-late/1097735/</a></p><p>“optimistic-people-have-one-thing-common-always-late”(乐观的人有一个共同点——总是迟到)</p><p>有意思。世界上没有什么标题比「你之所以[某个描述你的坏毛病],其实是因为你[某个好品质]」更棒的了。</p><p>我读了起来。结果发现,爱迟到的人其实是有史以来最棒的一群人。他们乐观、充满希望:</p><p><em>「习惯性迟到的人其实只是更乐观。他们相信自己能在有限的时间里塞进比别人更多的任务,而且在多任务处理时如鱼得水。简而言之,他们骨子里就是充满希望的。」</em></p><p>他们思维宏大:</p><p><em>「习惯性迟到的人不会为小事烦恼,他们专注于大局,把未来看作充满无限可能。」</em></p><p>爱迟到的人真的<em>懂</em>生活:</p><p><em>「有迟到倾向的人喜欢停下来闻闻玫瑰花香……生活本来就不是为了被规划到每个细节。过度依附时间表意味着无法享受当下。」</em></p><p>读完文章,我从未如此为自己是个慢性迟到者而感到自豪。</p><p>但同时,这他妈是在搞什么?爱迟到的人明明是<em>最讨厌</em>的。这是我身上<em>最不喜欢</em>的品质。而且我迟到不是因为我要闻玫瑰花,也不是因为我看得到大局,更不是因为未来充满无限可能。</p><p>我迟到是因为我有病。</p><p>于是我想了一分钟,觉得自己搞明白怎么回事了。问题在于,迟到分两种:</p><p><strong>1) 可以接受的迟到。</strong> 就是这个迟到的人迟到并不会对别人产生负面影响——比如群体聚会或派对迟到。事情可以准时开始,照常进行,不管这个迟到的人到没到。</p><p><strong>2) 不可接受的迟到。</strong> 就是这个迟到的人迟到<em>确实</em>会对别人产生负面影响——比如两人晚餐、会议,或任何非等迟到方到了才能开始的场合。</p><p>Haltiwanger 的文章(我希望)大部分讲的是<em>可以接受的</em>迟到。这样的话,行吧,也许那些人真的最棒,谁知道呢。</p><p>但如果你翻翻 Haltiwanger 文章底下的评论区,人们简直被他把迟到写得这么正面给气炸了。那是因为<em>他们</em>想的是那种远远不能被原谅的<em>不可接受的</em>迟到。</p><p>这一切让我别无选择,只能从进度浩大的 SpaceX 那篇文章里抽出短短九个小时,来聊聊<em>不可接受的</em>迟到人士。</p><p>说到那些慢性不可接受迟到者,我觉得可以分成两个子群体:</p><p><strong>第 1 组)那些不觉得自己有错、也不觉得愧疚的人。</strong> 这些人是混蛋。</p><p>**第二类) 因此感觉糟糕透顶、无比自厌的人。**这些人是有问题的。</p><p>第一类很简单。他们觉得自己比别人稍微特殊那么一点点,就像 Haltiwanger 那篇文章<a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Screen-Shot-2015-12-06-at-3.43.42-AM.png" target="_blank" rel="noreferrer">开头</a>那个毫无愧疚感的自恋狂。他们不讨人喜欢。没什么好多说的。</p><p>守时的人觉得<em>所有</em>不 OK 的迟到者都属于第一类(这篇文章的评论区一会儿就会证明这一点)——因为他们默认所有迟到者都是正常人。</p><p>一个正常人如果觉得某种行为没问题,就会去做;如果觉得不对,就不会做。所以在一个守时的人——一个准时出现是因为他相信迟到是不对的——看来,一个长期迟到的人肯定是个觉得迟到无所谓的混蛋。</p><p>但这就完全误解了第二群人,他们虽然经常迟到,却往往<em>痛恨</em>让别人等待这件事。我们就叫他们 CLIP 好了(Chronically Late Insane Person,慢性迟到症疯人)。</p><p>虽然两类不 OK 的迟到者最终都会经常让别人抓狂,但识别一个第二类 CLIP 有个可靠的方法:他们有一种诡异的、非要把自己搞砸不可的强迫倾向——某种深藏内心的驱动力,让他们莫名其妙地错过电影开头、经历精神崩溃式的狂奔去赶火车、亲手毁掉自己在职场上的口碑等等等等。他们伤害别人的同时,通常把自己伤得更狠。</p><p>我出身于一个 CLIP 世家。我童年大约有 15% 的时间是一个人站在某条人行道上,愤怒地踢着石子,因为<em>又一次</em>,其他孩子都被接走了,而我还在等我妈。等她终于来的时候,我不但没法愉快地跟她聊天,还怒气冲冲地钻进车里。她每次都感觉糟糕透顶。她是有问题的。</p><p>我姐有一次错过了一趟大清早的航班,于是航空公司把她改签到第二天早上。结果她<em>又</em>没赶上,又被安排到了 5 小时之后的航班。在漫长的候机时间里,她打了个长电话,打得忘乎所以,<em>那趟也错过了</em>。她是有问题的。</p><p>我这辈子一直是个 CLIP。我把一大堆朋友惹毛过,在职场场合一次又一次让自己下不来台,还在机场航站楼里累计跑完了一场马拉松。剧情通常一模一样,大概是这样:</p><p>我要跟某个人见面,比如说是个工作上的联系人,约在下午 3:00,地点是某家咖啡店。当我给这一天排日程时,我会想出一个完美的计划。我要早点出门,早点到,大概 2:45 就到。这样一来所有的压力都没了,而这正是理想状态,因为「不赶时间的通勤」是我最喜欢的事情之一。那会很棒——我会悠闲地走出去,打开一集播客,溜达到地铁站。下了地铁之后,时间还很充裕,我可以花几分钟逛逛橱窗,从街边小贩那儿买杯柠檬水,好好<em>享受一下纽约</em>。抬头看看建筑,听听街头的声响,感受人潮汹涌地从身边经过——啊,壮丽之城!</p><p>我只需要在 2:45 前下地铁就行了。要做到这一点,我得在 2:25 前上地铁,那么保险起见,2:15 之前到地铁站吧。所以我得在 2:07 或更早离开公寓,搞定。多完美的计划。以下是它实际上的走向(如果你是 WBW 的新读者,建议先<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">看看这个</a>再往下读):</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late1.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Late1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Latea.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Latea"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Lateb.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="Lateb"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Latec.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Latec"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late3.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Late3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late4.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="Late4"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late5.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Late5"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late6.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="Late6"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late7.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Late7"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late8.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="Late8"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late9.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="Late9"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late10.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt="Late10"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late16.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="Late16"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late17.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="Late17"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late18.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="Late18"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late19.png" target="_blank" rel="noreferrer"><img src="'+L+'" alt="Late19"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late20.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="Late20"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late21.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt="Late21"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late22.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt="Late22"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late23.png" target="_blank" rel="noreferrer"><img src="'+C+'" alt="Late23"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late24.png" target="_blank" rel="noreferrer"><img src="'+I+'" alt="Late24"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late25.png" target="_blank" rel="noreferrer"><img src="'+W+'" alt="Late25"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Late26.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt="Late26"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/PM1.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt="PM1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/PM2.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt="PM2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/PM31.png" target="_blank" rel="noreferrer"><img src="'+M+'" alt="PM3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/traffic1.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt="traffic"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Cab1.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt="Cab1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Cab2.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt="Cab2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/07/Cab31.png" target="_blank" rel="noreferrer"><img src="'+B+'" alt="Cab3"></a></p><p>CLIP 是一种奇怪的人。我敢说每个 CLIP 都有他们自己那份专属的疯,而要搞懂他们的运作方式,你通常得挖到内心某个阴暗的心理角落。对我来说,是这三个怪毛病的某种混合体:</p><p>**我迟到,是因为我对时间的运作方式处于否认状态。**CLIP 之所以总爱低估事情要花多久,来自于一种习惯性的、妄想式的乐观。通常情况是这样的:在这个 CLIP 做过某项活动或通勤过的所有次数里,他们记住的是最<em>快</em>的那一次。而<em>那个</em>时长,就深深烙在他们脑子里,成了这件事所需要的时间。我觉得<em>没有任何办法</em>能让我打心底里接受&quot;为一趟为期一周的旅行打包需要 20 分钟&quot;这个事实。在我脑海里,这永远是一个五分钟的任务。你就是把包拿出来,扔几件衣服进去,再把洗漱用品扔进去,拉上拉链,搞定。五分钟。至于那些经验数据显示打包时其实有一堆小事要考虑、每次都得花上 20 分钟——那都不重要。打包显然就是个五分钟的活儿。此刻我打这段字的时候,我依然这么相信。</p><p><strong>我迟到是因为我对情境切换有种奇怪的抵触。</strong> 不知道这是啥毛病,但我内心有种东西对「从当前正在做的事切换到另一件事」这个念头有种莫名其妙的反感。当我在家工作时,我<strong>恨死了</strong>日程表上有什么事情逼我必须停下所有事出门去做。倒不是我讨厌那个活动——真到了那儿我通常还挺高兴的——而是我对<strong>切换</strong>这件事有一种非理性的抗拒。这事的好处是,一旦我终于把屁股挪到某个地方去了,我通常会非常投入,而且我经常是最后一个走的。</p><p><strong>最后,我迟到是因为我对自己生气。</strong> 这里有一个相当强的相关性——我当天对自己的生产力越不满意,我就越可能迟到。当我对当天过得很满意的时候,理性决策者 (Rational Decision-Maker) 掌控方向盘就容易得多。我感觉自己像个成年人,所以做出成年人的行为就很容易。但那些猴子一整天骑在我头上作威作福的日子里,当我需要停下工作出门去某个地方的时刻到来时,我简直<strong>不敢相信</strong>我今天就<strong>只</strong>做了这么点事。于是我的大脑开始耍小脾气,拒绝接受这令人遗憾的处境,发起一场自我鞭挞式的抗议,说:「不行。情况绝对<strong>不能</strong>是这样。不行。你没有做到你本该做的事,所以你现在就坐在这儿再多做一点,哪怕会迟到。」</p><h2 id="所以嘛-这就是我为什么迟到——因为我是个疯子。不要为你生活里的-clip-找借口——这不-ok-他们需要改——但请记住-这不是你的问题。是他们有毛病。" tabindex="-1">所以嘛,这就是我为什么迟到——因为我是个疯子。不要为你生活里的 CLIP 找借口——这不 OK,他们需要改——但请记住,这不是你的问题。是他们有毛病。 <a class="header-anchor" href="#所以嘛-这就是我为什么迟到——因为我是个疯子。不要为你生活里的-clip-找借口——这不-ok-他们需要改——但请记住-这不是你的问题。是他们有毛病。" aria-label="Permalink to &quot;所以嘛,这就是我为什么迟到——因为我是个疯子。不要为你生活里的 CLIP 找借口——这不 OK,他们需要改——但请记住,这不是你的问题。是他们有毛病。&quot;">​</a></h2><p><strong>Wait But Why 上更多关于人类精神失常的讨论:</strong></p><p><strong><a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">拖延症患者为什么拖延 (Why Procrastinators Procrastinate)</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">为什么你该停止在乎别人怎么想 (Why You Should Stop Caring What Other People Think)</a></strong></p><h2 id="人生是一幅画-但你活在一个像素里-life-is-a-picture-but-you-live-in-a-pixel" tabindex="-1"><strong><a href="https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html" target="_blank" rel="noreferrer">人生是一幅画,但你活在一个像素里 (Life is a Picture But You Live in a Pixel)</a></strong> <a class="header-anchor" href="#人生是一幅画-但你活在一个像素里-life-is-a-picture-but-you-live-in-a-pixel" aria-label="Permalink to &quot;**[人生是一幅画,但你活在一个像素里 (Life is a Picture But You Live in a Pixel)](https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html)**&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发送给你。</p><p>如想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2015/07/why-im-always-late.html&amp;description=Why%20I%E2%80%99m%20Always%20Late" target="_blank" rel="noreferrer"><img src="'+O+'" alt=""></a></p>',77)])])}const U=a(K,[["render",$]]);export{R as __pageData,U as default};
